import { PlusIcon } from '@heroicons/react/outline';
import { useFormik } from 'formik';
import { useMutation } from 'react-query';

import { Button } from '@/components/Elements';
import { FormDrawer, Field, Dropzone, Textarea, Select } from '@/components/Form';
import { Authorization, ROLES } from '@/lib/authorization';
import { useNotificationStore } from '@/stores/notifications';
import { createCategorySchema } from '@/utils/yup';

import { createAchievement } from '../api';
import { SelectOption } from '@/types';
import { useState } from 'react';

interface FormikState {
  title: string;
  deleteImage: boolean;
  image: any;
  targettype: string;
  target: string;
  value: string;
  description: string;
}

export const CreateAchievementsIndividual = ({tagtitles, othertitles}) => {
  const { addNotification } = useNotificationStore();
  const [targetTitles, setTargetTitles] = useState(tagtitles);
  const { mutate, isLoading, isSuccess } = useMutation(createAchievement, {
    onSuccess: () => {
      formik.resetForm();
      addNotification({
        type: 'success',
        title: "Achievement successfully created.",
      });
    },
  });
  const initialValues: FormikState = {
    title: '',
    image: '',
    deleteImage: false,
    targettype: '',
    target: '',
    value: '1',
    description: '',
  };
  const optionTitles = ["Tags", "Others"];
  const formik = useFormik({
    initialValues,
    validationSchema: createCategorySchema,
    onSubmit: (v) => onSubmit(v),
  });
  const onSubmit = (value: any) => {
    mutate(value);
  };

  const onChangeSelect = (value: String) => {
    if(value == "Tags") {
      setTargetTitles(tagtitles);
    } else if (value == "Others") {
      setTargetTitles(othertitles);
    }
  }

  return (
    <Authorization allowedRoles={[ROLES.ADMIN]}>
      <FormDrawer
        isDone={isSuccess}
        triggerButton={
          <Button size="sm" variant="danger" startIcon={<PlusIcon className="h-4 w-4" />}>
            Create Achievement
          </Button>
        }
        title="Create Achievement"
        submitButton={
          <Button form="create-achievement" variant="danger" type="submit" size="sm" isLoading={isLoading}>
            Submit
          </Button>
        }
      >
        <form id="create-achievement" onSubmit={formik.handleSubmit}>
          <Field label="Title" formik={formik} name="title" />
          <Dropzone
            label="Thumbnail"
            name="image"
            formik={formik}
            defaultImg={formik.values.image}
            onDrop={(img) => formik.setFieldValue('image', img)}
            onDelete={() => formik.setValues({ ...formik.values, image: '', deleteImage: true })}
          />
          <Select
            formik={formik}
            label="Target type"
            name="targettype"
            options={optionTitles?.map((value) => ({ label: value, value: value })) || []}
            onChange={({ value }: SelectOption) => {
              formik.setFieldValue('targettype', value);
              onChangeSelect(value);
            }}
          />
          <Select
            formik={formik}
            label="Target"
            name="target"
            options={targetTitles?.map(({ title, id }) => ({ label: title, value: id })) || []}
            onChange={({ value }: SelectOption) => formik.setFieldValue('target', value)}
          />
          <Field label="Value" formik={formik} name="value" type ='number'/>
          <Textarea label="Description" formik={formik} name="description" />
        </form>
      </FormDrawer>
    </Authorization>
  );
};
